const hamMenu=document.getElementById("hamMenu"),offScreenNav=document.getElementById("offScreenNav"),handleHamAnimations=()=>{hamMenu.classList.toggle("animate"),offScreenNav.classList.toggle("show")};hamMenu.addEventListener("click",handleHamAnimations),offScreenNav.addEventListener("click",handleHamAnimations);const particalBoard=document.querySelector(".partical-board"),config={particalCount:5e3};for(let a=0;a<config.particalCount;a++)createPartical(),positionPartical();function createPartical(){let a=document.createElement("div");a.classList.add("partical"),particalBoard.appendChild(a)}function positionPartical(a){document.querySelectorAll(".partical").forEach((a=>{let t=Math.floor(-1e3*Math.random()+500);a.style.top=`${t}%`;let e=Math.floor(-1e3*Math.random()+500);a.style.left=`${e}%`;let n=Math.floor(20*Math.random()),o=Math.floor(10*Math.random());a.style.animation=`particals ${n}s ${o}s ease infinite`}))}